import FixtureRow from './fixture-row';
import { Fixture } from '../../objects/fixture';
import { GameType } from '../../objects/enums/enums';

interface FixtureComponentProps{
    fixtures : Fixture[],
    gameType : GameType
}

// You have to pass in the props and say that props evaluates to fixturesToShow which is of type Fixture[]
const FixtureTable = (fixturesProps : FixtureComponentProps) => {      

    console.log(fixturesProps.fixtures.length + " Stu");
    console.log(fixturesProps.fixtures);
    // useState is a hook. Must be first line of the function. 
    // useState(xxx) - xxx is the original collection
    // [fixtures,...] - fixtures is the current copy of it. This will get updated by using setFixture
    // [..., setFixture] - is a function used to update the fixtures array.
   // const [fixtures, setFixture] = useState(fixturesToShow);   
    return(
        <>                       
        <div className="row">            
            <div>
                
                <table className="table table-hover table-condensed table-responsive">
                    <thead>
                        <tr>
                            <th>Date</th>
                            <th>Result</th>
                            <th>Home Team</th>
                            <th></th>
                            <th></th>                                                                                                 
                            <th></th>  
                            <th>Away Team</th>  
                        </tr>
                    </thead>
                    <tbody>

                        {(fixturesProps.fixtures === undefined) ? <FixtureRow fixture={fixturesProps.fixtures[0]} /> : <div>123</div> }
                                
                          
                    </tbody>
                </table>                          
            </div>
        </div>                
        </>
    );
}
export default FixtureTable;


